// <house-md> — the form-associated custom element that ties everything
// together. Owns the Document, the input handlers, and the IME
// composition lifecycle.
//
// IME / dead-key composition (e.g. macOS Option+E + e → é) is handled
// here, not in InputHandler. The strategy:
//
//   compositionstart  — set composing=true, snapshot the pre-composition
//                       Selection range. From this point on, beforeinput
//                       does NOT preventDefault, so the browser drives
//                       the contenteditable display natively.
//   compositionend    — reset the History throttle, replace the snapshot
//                       range with event.data, re-render. The content
//                       model converges with the live DOM.
//
// We also moved internals.setFormValue() off the typing path. It now
// fires on `formdata`, which is the canonical "give me the latest
// value before submission" hook used by native submit, requestSubmit,
// and `new FormData(form)`.

import { Document } from "./document.js"
import { Selection } from "./selection.js"
import { InputHandler } from "./input_handler.js"
import { ActionHandler } from "./action_handler.js"
import { DragAndDropHandler } from "./drag_and_drop.js"

const KEYBOARD_SHORTCUTS = {
  "Ctrl+B": "bold",
  "Ctrl+I": "italic",
  "Ctrl+S": "strikethrough",
  "Ctrl+Z": "undo",
  "Ctrl+Shift+Z": "redo",
}

export class Editor extends HTMLElement {
  static formAssociated = true

  constructor() {
    super()
    this.internals = this.attachInternals()
    this.internals.ariaRole = "textbox"
    this.composing = false
    this.compositionStartRange = null
  }

  connectedCallback() {
    const initialContent = this.querySelector(".house-md-content")?.textContent || this.textContent
    this.document = new Document(initialContent, this)
    this.installShell()
    this.attachEventListeners()
    this.inputHandler = new InputHandler(this.document)
    this.actionHandler = new ActionHandler(this.document)
    this.dropAndDropHandler = new DragAndDropHandler(this)
    if (this.autofocus) this.focus()
    this.setAttribute("initialized", "")
    this.value = initialContent
  }

  disconnectedCallback() {
    this.detachEventListeners()
  }

  validate = (event) => {
    if (this.required && this.document.isEmpty) {
      event.preventDefault()
      this.internals.setValidity({ valueMissing: true }, "This field is required.", this.contentWrapper)
      this.focus()
    } else {
      this.internals.setValidity({})
    }
  }

  render() {
    this.document.render()
  }

  focus() {
    this.contentWrapper.focus()
  }

  get required() {
    return this.hasAttribute("required")
  }

  set required(value) {
    if (value) this.setAttribute("required", "")
    else this.removeAttribute("required")
  }

  get autofocus() {
    return this.hasAttribute("autofocus")
  }

  set autofocus(value) {
    if (value) this.setAttribute("autofocus", "")
    else this.removeAttribute("autofocus")
  }

  get value() {
    return this.document.content
  }

  // setFormValue used to fire on every keystroke because the original
  // commit path did `this.element.value = t`, which routed through this
  // setter. The new commit path mutates the Document directly and
  // bypasses the setter, so typing no longer pays this cost. The
  // `formdata` listener (syncFormValue) flushes the latest content
  // before submission. setFormValue is still called here for direct
  // external assignments.
  set value(text) {
    this.document.content = text
    this.internals.setFormValue(text)
    this.internals.setValidity({})
    this.render()
  }

  get form() {
    return this.internals.form
  }

  installShell() {
    this.textContent = ""
    this.toolbar = this.findOrCreateToolbar()
    this.contentWrapper = document.createElement("div")
    this.contentWrapper.classList.add("house-md-content")
    this.contentWrapper.setAttribute("contenteditable", "true")
    this.append(this.contentWrapper)
    if (!this.getAttribute("tabindex")) this.contentWrapper.setAttribute("tabindex", "0")
  }

  findOrCreateToolbar() {
    const externalId = this.getAttribute("toolbar")
    if (externalId) return document.getElementById(externalId)
    const toolbar = document.createElement("house-md-toolbar")
    this.prepend(toolbar)
    return toolbar
  }

  attachEventListeners() {
    this.addEventListener("beforeinput", this.onBeforeInput)
    this.addEventListener("compositionstart", this.onCompositionStart)
    this.addEventListener("compositionend", this.onCompositionEnd)
    this.addEventListener("keydown", this.onKeyDown)
    this.addEventListener("dragover", this.onDragOver)
    this.addEventListener("drop", this.onDrop)
    this.toolbar.addEventListener("house-md:toolbar-action", this.onToolbarAction)
    document.addEventListener("selectionchange", this.onSelectionChange)
    if (this.internals.form) {
      this.internals.form.addEventListener("submit", this.validate)
      this.internals.form.addEventListener("formdata", this.syncFormValue)
    }
  }

  detachEventListeners() {
    this.removeEventListener("beforeinput", this.onBeforeInput)
    this.removeEventListener("compositionstart", this.onCompositionStart)
    this.removeEventListener("compositionend", this.onCompositionEnd)
    this.removeEventListener("keydown", this.onKeyDown)
    this.removeEventListener("dragover", this.onDragOver)
    this.removeEventListener("drop", this.onDrop)
    this.toolbar.removeEventListener("house-md:toolbar-action", this.onToolbarAction)
    document.removeEventListener("selectionchange", this.onSelectionChange)
    if (this.internals.form) {
      this.internals.form.removeEventListener("submit", this.validate)
      this.internals.form.removeEventListener("formdata", this.syncFormValue)
    }
  }

  onBeforeInput = (event) => {
    this.inputHandler.handleInput(event, this.contentWrapper, this.document.blocks)
  }

  onCompositionStart = () => {
    this.composing = true
    const live = window.getSelection()
    if (live && live.rangeCount > 0) {
      this.compositionStartRange = Selection.fromDOMRange(
        live.getRangeAt(0),
        this.contentWrapper,
        this.document.blocks,
      )
    } else {
      const { start, end } = this.document.currentSelection
      this.compositionStartRange = { start, end }
    }
  }

  onCompositionEnd = (event) => {
    const snapshot = this.compositionStartRange
    this.composing = false
    this.compositionStartRange = null
    if (!snapshot) return
    // Reset the History throttle so the upcoming replaceText records a
    // new undo entry covering the entire composition rather than being
    // dropped if a recent typing burst left the throttle armed.
    this.document.history.resetThrottle()
    this.document.replaceText(event.data || "", snapshot.start, snapshot.end)
  }

  onKeyDown = (event) => {
    const action = KEYBOARD_SHORTCUTS[shortcutKey(event)]
    if (!action) return
    event.preventDefault()
    // Stop the consumed shortcut from bubbling to global/@window listeners
    // (e.g. an app sidebar bound to Ctrl+B). Keys the editor does NOT handle
    // fall through above and keep bubbling, so non-editor shortcuts still work.
    event.stopPropagation()
    this.actionHandler.handleAction(action)
  }

  onDragOver = (event) => {
    this.dropAndDropHandler.handleDragOver(event)
  }

  onDrop = (event) => {
    this.dropAndDropHandler.handleDrop(event)
  }

  onToolbarAction = ({ detail }) => {
    this.actionHandler.handleAction(detail.houseMdAction, detail)
  }

  onSelectionChange = () => {
    if (this.composing) return
    this.document.selection.update()
  }

  syncFormValue = (event) => {
    const value = this.document.content
    this.internals.setFormValue(value)
    // A form-associated element's submission value is collected into the entry
    // list BEFORE the `formdata` event fires, so setFormValue() alone does not
    // affect the in-flight submission (native submit, requestSubmit, or
    // `new FormData(form)` as Turbo uses). Update the event's FormData directly
    // — keyed by our `name` — so the latest content is actually submitted.
    const name = this.getAttribute("name")
    if (event?.formData && name) event.formData.set(name, value)
  }
}

function shortcutKey(event) {
  const parts = []
  if (event.metaKey || event.ctrlKey) parts.push("Ctrl")
  if (event.altKey) parts.push("Alt")
  if (event.shiftKey) parts.push("Shift")
  parts.push(event.key.toUpperCase())
  return parts.join("+")
}

customElements.define("house-md", Editor)
